    60→static bool immed_can_modify(u64 instr)
    61→{
    62→	if (FIELD_GET(OP_IMMED_INV, instr) ||
    63→	    FIELD_GET(OP_IMMED_SHIFT, instr) ||
    64→	    FIELD_GET(OP_IMMED_WIDTH, instr) != IMMED_WIDTH_ALL) {
    65→		pr_err("Can't decode/encode immed!\n");
    66→		return false;
    67→	}
